<?php
namespace Database\Seeders;
use App\Models\PostCategory;use App\Models\System as BusinessSystem;use App\Models\User;use Illuminate\Database\Seeder;
class SystemSeeder extends Seeder{public function run():void{$admin=User::first();$cat=PostCategory::where('slug','services-systems')->first();$items=['سامانه نوین اصناف','سامانه ایرانیان اصناف','سامانه آموزش اصناف','سامانه ثبت شکایات','سامانه بازرسی','سامانه اطلاع‌رسانی اتحادیه‌ها'];foreach($items as $i=>$title){BusinessSystem::updateOrCreate(['slug'=>'system-'.($i+1)],['title'=>$title,'description'=>'سامانه نمونه برای دسترسی سریع کاربران به خدمات و اطلاعات صنفی شهرستان گرگان.','short_description'=>'دسترسی سریع به '.$title,'icon'=>['💻','🌐','🎓','📨','🔍','📢'][$i],'image'=>'assets/img/asnaf-gorgan-default.jpg','link'=>'https://example.com','category_id'=>$cat?->id,'target'=>'_blank','status'=>'published','published_at'=>now()->subDays($i),'created_by'=>$admin?->id,'approved_by'=>$admin?->id,'sort_order'=>$i+1,'is_active'=>true]);}}}
